const proc = $('Process Session').first().json;
const text = (proc.text || '').toString();
const tableMatch = text.match(/\d+/);
if (!tableMatch) return [{ json: { ...proc, error: 'INVALID_TABLE', error_msg: `❌ Please enter a valid table number (1-${$env.MAX_TABLES})\n\nExample: 'Table 5' or just '5'` } }];
const tableNum = parseInt(tableMatch[0]);
if (isNaN(tableNum)) return [{ json: { ...proc, error: 'INVALID_TABLE', error_msg: '❌ Table number must be a valid number' } }];
const maxTables = parseInt($env.MAX_TABLES || '200');
if (tableNum < 1 || tableNum > maxTables) return [{ json: { ...proc, error: 'TABLE_OUT_OF_RANGE', error_msg: `❌ Table number must be between 1 and ${maxTables}` } }];
return [{ json: { ...proc, table_number: tableNum } }];

const session = $input.item.json.session || {};
session.table_number = $input.item.json.table_number;
return [{json: {...$input.item.json, session}}];

const inputData = $('Restore Session After Save').first().json;
const menuItems = $input.all();
if (!menuItems || menuItems.length === 0) return [{json: {...inputData, error: 'NO_MENU', error_msg: '❌ Menu not available. Please try again.'}}];

let rows = [];
menuItems.forEach(item => {
    rows.push({
        id: "CMD_ADD_" + item.json.code,
        title: item.json.name.substring(0, 24),
        description: ('₹' + item.json.price + ' - ' + item.json.category).substring(0, 72)
    });
});

rows = rows.slice(0, 10); // WhatsApp interactive list limit

const interactive = {
    type: "list",
    header: {type: "text", text: "📋 " + ($env.RESTAURANT_NAME || 'Menu')},
    body: {text: "Select an item to add to your cart or type your order.\nExample: '2 B1s and a D2'"},
    action: {
        button: "View Items",
        sections: [{title: "Available Items", rows}]
    }
};

return [{json: {...inputData, interactive}}];

const data = $input.item.json;
let parsed_items = [];
try {
    const content = data.choices[0].message.content;
    const arrayMatch = content.match(/\[.*\]/s);
    if (arrayMatch) {
       parsed_items = JSON.parse(arrayMatch[0]);
    } else {
       parsed_items = JSON.parse(content);
    }
} catch (e) {
    return [{json: {...data, error: 'AI_PARSE_ERROR', error_msg: '❌ We had trouble understanding your order.\n\nTry sending codes like: B10, A5'}}];
}

if (!Array.isArray(parsed_items) || parsed_items.length === 0) {
    return [{json: {...data, error: 'NO_ITEMS', error_msg: '❌ No items found in your message.\n\nTry sending codes like: B10, A5'}}];
}

parsed_items = parsed_items.map(i => ({...i, quantity: parseInt(i.quantity) || 1}));

return [{json: {...data, parsed_items}}];

const inputData = $('Extract Groq Output').first().json;
const parsed_items = inputData.parsed_items || [];
const dbItems = $input.all().map(i => i.json);

if (!dbItems || dbItems.length === 0) return [{json: {...inputData, error: 'ITEMS_NOT_FOUND', error_msg: '❌ No valid items found\n\nType MENU to see available items'}}];

const session = inputData.session || {};
const cart = session.cart || [];
let outOfStock = [];
let itemsAdded = [];

dbItems.forEach(dbItem => {
  const requested = parsed_items.find(pi => pi.code === dbItem.code);
  const qty = requested ? requested.quantity : 1;

  if (!dbItem.is_available) {
     outOfStock.push(dbItem.name);
  } else {
     itemsAdded.push(qty + "x " + dbItem.name);
     const existing = cart.find(c => c.code === dbItem.code);
     if (existing) { existing.quantity += qty; } else {
        cart.push({...dbItem, quantity: qty, id: Date.now() + Math.random()});
     }
  }
});

session.cart = cart;

if (itemsAdded.length === 0 && outOfStock.length > 0) {
    return [{json: {...inputData, error: 'ALL_OUT_OF_STOCK', error_msg: '⚠️ Sorry, everything you requested (' + outOfStock.join(', ') + ') is currently sold out.'}}];
}

const subtotal = cart.reduce((sum, i) => sum + ((i.price || 0) * (i.quantity || 1)), 0);
const taxRate = parseFloat($('Get Restaurant Config').item.json.tax_rate || '0') / 100;
const tax = Math.round(subtotal * taxRate);
const total = subtotal + tax;

return [{json: {...inputData, session, cart, subtotal, tax, total, items_added: itemsAdded, out_of_stock: outOfStock}}];

